barrier.dstQueueFamilyIndex = VK_QUEUE_FAMILY_IGNORED;
// لا يوجد نقل ملكية بين الطوابير

// نقل ملكية Buffer من طابور داخلي لخارجي
VkBufferMemoryBarrier barrier = {};
barrier.srcQueueFamilyIndex = graphicsQueueFamilyIndex;  // طابورنا
barrier.dstQueueFamilyIndex = VK_QUEUE_FAMILY_EXTERNAL;  // طابور خارجي

// أو العكس: استقبال من طابور خارجي
barrier.srcQueueFamilyIndex = VK_QUEUE_FAMILY_EXTERNAL;
barrier.dstQueueFamilyIndex = graphicsQueueFamilyIndex;

VkImageViewCreateInfo createInfo = {};
createInfo.subresourceRange.baseMipLevel = 0;  // البدء من أول مستوى
createInfo.subresourceRange.levelCount = VK_REMAINING_MIP_LEVELS;  // جميع المستويات

