}

// التحقق من دعم الامتداد
uint32_t extensionCount;
vkEnumerateDeviceExtensionProperties(device, nullptr, &extensionCount, nullptr);
std::vector<VkExtensionProperties> extensions(extensionCount);
vkEnumerateDeviceExtensionProperties(device, nullptr, &extensionCount, extensions.data());

bool swapchainSupported = false;
for (const auto& ext : extensions) {
    if (strcmp(ext.extensionName, VK_KHR_SWAPCHAIN_EXTENSION_NAME) == 0) {
        swapchainSupported = true;
        break;
    }
}

// تفعيل الامتداد
const char* deviceExtensions[] = {
    VK_KHR_SWAPCHAIN_EXTENSION_NAME
};

VkDeviceCreateInfo createInfo = {};
createInfo.enabledExtensionCount = 1;
createInfo.ppEnabledExtensionNames = deviceExtensions;

// التحقق من إصدار الامتداد
VkExtensionProperties props;
// ... الحصول على الخصائص

if (props.specVersion >= VK_KHR_SWAPCHAIN_SPEC_VERSION) {
    // الإصدار مدعوم
}

VkPipelineColorBlendAttachmentState blendAttachment = {};
// كتابة جميع المكونات
blendAttachment.colorWriteMask = VK_COLOR_COMPONENT_R_BIT | 
                                  VK_COLOR_COMPONENT_G_BIT | 
                                  VK_COLOR_COMPONENT_B_BIT | 
                                  VK_COLOR_COMPONENT_A_BIT;

// كتابة الأحمر فقط
blendAttachment.colorWriteMask = VK_COLOR_COMPONENT_R_BIT;

// كتابة RGB بدون Alpha
blendAttachment.colorWriteMask = VK_COLOR_COMPONENT_R_BIT | 
                                  VK_COLOR_COMPONENT_G_BIT | 
                                  VK_COLOR_COMPONENT_B_BIT;
// أو إضافة Alpha
blendAttachment.colorWriteMask |= VK_COLOR_COMPONENT_A_BIT;

// انتظار في بداية Pipeline
VkSubmitInfo submitInfo = {};
VkPipelineStageFlags waitStages[] = { VK_PIPELINE_STAGE_TOP_OF_PIPE_BIT };
submitInfo.pWaitDstStageMask = waitStages;

// هذا يعني: يمكن البدء فوراً عند استقبال الإشارة

