    VK_PIPELINE_STAGE_COLOR_ATTACHMENT_OUTPUT_BIT 
};
submitInfo.pWaitDstStageMask = waitStages;

// هذا يضمن عدم الكتابة للصورة قبل أن تكون جاهزة

// حاجز للوصول للـ Textures في Fragment Shader
VkImageMemoryBarrier barrier = {};
barrier.dstAccessMask = VK_ACCESS_SHADER_READ_BIT;

// في vkCmdPipelineBarrier
vkCmdPipelineBarrier(
    commandBuffer,
    VK_PIPELINE_STAGE_TRANSFER_BIT,           // بعد النسخ
    VK_PIPELINE_STAGE_FRAGMENT_SHADER_BIT,    // قبل استخدام Fragment Shader
    0, 1, nullptr, 0, nullptr, 1, &barrier
);

// حاجز لتحديث Vertex Buffer
VkBufferMemoryBarrier barrier = {};
barrier.srcAccessMask = VK_ACCESS_TRANSFER_WRITE_BIT;  // بعد النسخ
barrier.dstAccessMask = VK_ACCESS_VERTEX_ATTRIBUTE_READ_BIT;  // للقراءة

vkCmdPipelineBarrier(
    commandBuffer,
    VK_PIPELINE_STAGE_TRANSFER_BIT,
    VK_PIPELINE_STAGE_VERTEX_INPUT_BIT,
    0, 0, nullptr, 1, &barrier, 0, nullptr
);

VkSubpassDependency dependency = {};
dependency.dstAccessMask = VK_ACCESS_COLOR_ATTACHMENT_WRITE_BIT;
dependency.dstStageMask = VK_PIPELINE_STAGE_COLOR_ATTACHMENT_OUTPUT_BIT;

// هذا يسمح بالكتابة لمرفق اللون

// تجهيز Texture للقراءة في Shader
